  ? "SELECT Id, Lead_Email__c, Related_Lead__c, Meeting_Start_Date_Time__c, Meeting_End_Date_Time__c, Meeting_Timezone__c, Meeting_Source__c, Calendly_Confirmation_Sent__c FROM Meeting_Reminder_Tracker__c WHERE Id = '" + $('Confirmation Email Config').item.json.testRecordId + "' AND Meeting_Source__c = 'Calendly' LIMIT 1"
  : "SELECT Id, Lead_Email__c, Related_Lead__c, Meeting_Start_Date_Time__c, Meeting_End_Date_Time__c, Meeting_Timezone__c, Meeting_Source__c, Calendly_Confirmation_Sent__c FROM Meeting_Reminder_Tracker__c WHERE Meeting_Source__c = 'Calendly' AND Meeting_Status__c = 'Scheduled' AND Calendly_Confirmation_Sent__c = false AND Related_Lead__c != null AND Lead_Email__c != null AND Meeting_Start_Date_Time__c != null LIMIT " + $('Confirmation Email Config').item.json.batchLimit }}

parameters.jsCode:
const cfg = $('Confirmation Email Config').item.json;
const trackerItems = $('Query Eligible Calendly Trackers').all();
const leadItems = $input.all();

const senderSig = '<table cellpadding="0" cellspacing="0" border="0" style="font-family: Arial, sans-serif; font-size: 13px; color: #333333; line-height: 1.4;"><tr><td style="padding-bottom: 8px;"><img src="https://example.com/logo-placeholder.png" alt="Example Company" width="200" style="display: block; border: 0;" /></td></tr><tr><td><strong style="font-size: 14px;">Example User</strong></td></tr><tr><td><em>Founder &amp; CEO</em></td></tr><tr><td style="padding-top: 6px;"><a href="mailto:user@example.com" style="color: #333333; text-decoration: none;">user@example.com</a></td></tr><tr><td>O 555 010 0001</td></tr><tr><td>M 555 010 0002</td></tr><tr><td><a href="https://example.com/" style="color: #0066CC; text-decoration: underline;">example.com</a></td></tr><tr><td style="padding-top: 8px;"><a href="https://calendly.com/example-user/30-min" style="color: #0066CC; font-weight: bold; text-decoration: none;">Book a meeting here</a></td></tr></table>';

const results = [];

for (let i = 0; i < trackerItems.length; i++) {
  const tracker = trackerItems[i].json;
  const lead = leadItems[i] ? leadItems[i].json : {};

  if (tracker.Meeting_Source__c !== 'Calendly') continue;

  const tz = tracker.Meeting_Timezone__c || 'America/Los_Angeles';
  const startISO = tracker.Meeting_Start_Date_Time__c || '';
  let readableDateTime = startISO;
  try {
    const dt = new Date(startISO);
    readableDateTime = dt.toLocaleString('en-US', {
      timeZone: tz,
      weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
      hour: 'numeric', minute: '2-digit', timeZoneName: 'short'
    });
  } catch(e) {}

  const firstName = String(lead.FirstName || lead.Name || 'there');
  const leadEmail = String(tracker.Lead_Email__c || lead.Email || '');

  const subject = 'Your meeting with Example Company is confirmed';

  const bodyHtml =
    '<p>Hi ' + firstName + ',</p>'
    + '<p>Thank you for scheduling a meeting with Example Company. This confirms that your meeting has been booked.</p>'
    + '<p><strong>Meeting Details:</strong><br>'
    + 'Date/Time: ' + readableDateTime + '</p>'
    + '<p>We look forward to speaking with you.</p>'
    + '<br>' + senderSig;

  results.push({ json: {
    trackerId: String(tracker.Id || ''),
    leadId: String(tracker.Related_Lead__c || ''),
    leadEmail,
    firstName,
    toAddress: leadEmail,
    ccList: String(cfg.colleagueEmail || 'colleague@example.com'),
    subject,
    bodyHtml,
    readableDateTime,
    meetingTimezone: tz,
    senderEmail: String(cfg.senderEmail || ''),
    colleagueEmail: String(cfg.colleagueEmail || '')
  }});
}

return results.length > 0 ? results : [{ json: { noEligibleTrackers: true } }];
